    41|  Home,
    42|} from 'lucide-react-native';
    43|import * as Haptics from 'expo-haptics';
    44|import { useQuery } from '@tanstack/react-query';
    45|
    46|import Colors from '@/constants/colors';
    47|import { fetchVideoFeed, fetchProjectReels, type FeedVideo } from '@/lib/video-feed';
    48|import {
    49|  toggleProjectLike,
    50|  trackProjectShare,
    51|  fetchProjectComments,
    52|  addProjectComment,
    53|  deleteProjectComment,
    54|  type ProjectComment,
    55|} from '@/lib/project-engagement';
    56|import {
    57|  toggleVideoSave,
    58|  toggleVideoFollow,
    59|  reportVideo,
    60|  trackVideoEvent,
    61|  getViewerId,
    62|  buildVideoShareUrl,
    63|} from '@/lib/video-platform';
    64|import ProjectCommentsSheet from '@/components/ProjectCommentsSheet';
    65|import ProjectShareSheet from '@/components/ProjectShareSheet';
    66|import SafeVideo from '@/components/SafeVideo';
    67|import { supabase } from '@/lib/supabase';
    68|
    69|const GOLD = Colors.primary;
    70|const LIKE_RED = Colors.error;
    71|
    72|interface EngagementState {
    73|  likeCount: number;
    74|  commentCount: number;
    75|  shareCount: number;
    76|  saveCount: number;
    77|  liked: boolean;
    78|  saved: boolean;
    79|  following: boolean;
    80|}
    81|
    82|function formatCount(n: number): string {
    83|  if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
    84|  if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
    85|  return String(n);
    86|}
    87|
    88|function compactCurrency(value: number): string {
    89|  if (value >= 1_000_000) {
    90|    const m = value / 1_000_000;
    91|    return `$${m % 1 === 0 ? m.toFixed(0) : m.toFixed(1)}M`;
    92|  }
    93|  if (value >= 1_000) {
    94|    const k = value / 1_000;
    95|    return `$${k % 1 === 0 ? k.toFixed(0) : k.toFixed(1)}K`;
    96|  }
    97|  return `$${Math.round(value)}`;
    98|}
    99|
   100|function parseVideoTitle(video: FeedVideo): { title: string; location: string | null; tourLabel: string } {
   101|  const raw = video.title ?? video.deal?.title ?? 'IVX Holdings';
   102|  const locationMatch = raw.match(/(.+?)\s*[—–]\s*([^,]+,\s*[A-Z]{2})/);
   103|  if (locationMatch) {
   104|    return { title: locationMatch[1].trim(), location: locationMatch[2].trim(), tourLabel: 'Property Tour' };
   105|  }
   106|  const tourMatch = raw.match(/(.+?)\s*[—–]\s*(.+)/);
   107|  if (tourMatch) {
   108|    const tour = tourMatch[2].trim();
   109|    const isLocation = /,\s*[A-Z]{2}/.test(tour);
   110|    return { title: tourMatch[1].trim(), location: isLocation ? tour : null, tourLabel: isLocation ? 'Property Tour' : tour };
   111|  }
   112|  return { title: raw, location: null, tourLabel: 'Property Tour' };
   113|}
   114|
   115|function useInvestmentOptions(dealType: string | null | undefined) {
   116|  const t = (dealType ?? '').toLowerCase();
   117|  const tokenized = { id: 'tokenized', label: 'Tokenized', icon: <Hexagon size={16} color={GOLD} />, tint: GOLD };
   118|  const jvDeals = { id: 'jvDeals', label: 'JV Deal', icon: <Users size={16} color={Colors.blue} />, tint: Colors.blue };
   119|  const buyers = { id: 'buyers', label: 'Buyer', icon: <Home size={16} color={Colors.green} />, tint: Colors.green };
   120|  switch (t) {
   121|    case 'jv':
   122|    case 'equity_split':
   123|    case 'hybrid':
   124|      return [tokenized, jvDeals, buyers];
   125|    case 'development':
   126|    case 'new_construction':
   127|    case 'rehab_construction':
   128|      return [jvDeals, tokenized, buyers];
   129|    case 'profit_sharing':
   130|      return [tokenized, buyers, jvDeals];
   131|    default:
   132|      return [tokenized, jvDeals, buyers];
   133|  }
   134|}
   135|
   136|type ReelChannel = 'all' | 'investment' | 'buyer' | 'seller';
   137|
   138|const CHANNELS: { id: ReelChannel; label: string }[] = [
   139|  { id: 'all', label: 'All' },
   140|  { id: 'investment', label: 'Investments' },
   141|  { id: 'buyer', label: 'Buyers' },
   142|  { id: 'seller', label: 'Sellers' },
   143|];
   144|
   145|interface FeedItemProps {
   146|  video: FeedVideo;
   147|  isActive: boolean;
   148|  height: number;
   149|  muted: boolean;
   150|  engagement: EngagementState;
   151|  onToggleMute: () => void;
   152|  onLike: (video: FeedVideo) => void;
   153|  onDoubleTapLike: (video: FeedVideo) => void;
   154|  onComment: (video: FeedVideo) => void;
   155|  onShare: (video: FeedVideo) => void;
   156|  onSave: (video: FeedVideo) => void;
   157|  onFollow: (video: FeedVideo) => void;
   158|  onReport: (video: FeedVideo) => void;
   159|  onViewDeal: (video: FeedVideo) => void;
   160|  onInvestNow: (video: FeedVideo) => void;
   161|}
   162|
   163|const FeedItem = React.memo(function FeedItem({
   164|  video,
   165|  isActive,
   166|  height,
   167|  muted,
   168|  engagement,
   169|  onToggleMute,
   170|  onLike,
   171|  onDoubleTapLike,
   172|  onComment,
   173|  onShare,
   174|  onSave,
   175|  onFollow,
   176|  onReport,
   177|  onViewDeal,
   178|  onInvestNow,
   179|}: FeedItemProps) {
   180|  const [paused, setPaused] = useState<boolean>(false);
   181|  const [showHeart, setShowHeart] = useState<boolean>(false);
   182|  const [progress, setProgress] = useState<number>(0);
   183|  const insets = useSafeAreaInsets();
   184|  const lastTapRef = useRef<number>(0);
   185|  const shouldPlay = isActive && !paused;
   186|
   187|  const deal = video.deal ?? null;
   188|  const investmentOptions = useInvestmentOptions(deal?.deal_type);
   189|
   190|  const handleTap = () => {
   191|    const now = Date.now();
   192|    if (now - lastTapRef.current < 320) {
   193|      lastTapRef.current = 0;
   194|      setShowHeart(true);
   195|      setTimeout(() => setShowHeart(false), 800);
   196|      onDoubleTapLike(video);
   197|    } else {
   198|      lastTapRef.current = now;
   199|      setTimeout(() => {
   200|        if (lastTapRef.current === now) {
   201|          setPaused(p => !p);
   202|        }
   203|      }, 330);
   204|    }
   205|  };
   206|
   207|  const parsed = parseVideoTitle(video);
   208|  const propertyTitle = deal?.title ?? parsed.title;
   209|  const isActiveStatus = (video.status ?? 'published') === 'published';
   210|
   211|  return (
   212|    <View style={[styles.item, { height }]}>
   213|      <TouchableOpacity
   214|        style={StyleSheet.absoluteFill}
   215|        activeOpacity={1}
   216|        onPress={handleTap}
   217|        onLongPress={() => onReport(video)}
   218|        testID={`video-item-${video.id}`}
   219|      >
   220|        <SafeVideo
   221|          uri={video.hls_url ?? video.video_url}
   222|          posterUri={video.poster_url ?? video.thumbnail_url ?? video.preview_blur_url}
   223|          style={StyleSheet.absoluteFill}
   224|          resizeMode={ResizeMode.COVER}
   225|          shouldPlay={shouldPlay}
   226|          isMuted={muted}
   227|          onProgress={(progress) => setProgress(progress)}
   228|          testID={`video-player-${video.id}`}
   229|        />
   230|      </TouchableOpacity>
   231|
   232|      {/* Progress bar */}
   233|      <View style={styles.progressBar}>
   234|        <View style={[styles.progressFill, { width: `${progress * 100}%` }]} />
   235|      </View>
   236|
   237|      {!shouldPlay && (
   238|        <View pointerEvents="none" style={styles.centerPlay}>
   239|          <View style={styles.centerPlayCircle}>
   240|            <Play size={30} color="#000" fill="#000" />
   241|          </View>
   242|        </View>
   243|      )}
   244|
   245|      {showHeart && (
   246|        <View pointerEvents="none" style={styles.burstHeart}>
   247|          <Heart size={96} color={LIKE_RED} fill={LIKE_RED} />
   248|        </View>
   249|      )}
   250|
   251|      {/* Right action rail */}
   252|      <View style={[styles.rail, { bottom: insets.bottom + 96 }]}>
   253|        <TouchableOpacity
   254|          style={styles.railBtn}
   255|          onPress={() => onLike(video)}
   256|          testID={`video-like-${video.id}`}
   257|        >
   258|          <Heart
   259|            size={30}
   260|            color={engagement.liked ? LIKE_RED : '#fff'}
   261|            fill={engagement.liked ? LIKE_RED : 'transparent'}
   262|          />
   263|          <Text style={styles.railCount}>{formatCount(engagement.likeCount)}</Text>
   264|        </TouchableOpacity>
   265|
   266|        <TouchableOpacity
   267|          style={styles.railBtn}
   268|          onPress={() => onComment(video)}
   269|          testID={`video-comment-${video.id}`}
   270|        >
   271|          <MessageCircle size={30} color="#fff" />
   272|          <Text style={styles.railCount}>{formatCount(engagement.commentCount)}</Text>
   273|        </TouchableOpacity>
   274|
   275|        <TouchableOpacity
   276|          style={styles.railBtn}
   277|          onPress={() => onSave(video)}
   278|          testID={`video-save-${video.id}`}
   279|        >
   280|          <Bookmark
   281|            size={30}
   282|            color={engagement.saved ? GOLD : '#fff'}
   283|            fill={engagement.saved ? GOLD : 'transparent'}
   284|          />
   285|          <Text style={styles.railCount}>{formatCount(engagement.saveCount)}</Text>
   286|        </TouchableOpacity>
   287|
   288|        <TouchableOpacity
   289|          style={styles.railBtn}
   290|          onPress={() => onShare(video)}
   291|          testID={`video-share-${video.id}`}
   292|        >
   293|          <Share2 size={30} color="#fff" />
   294|          <Text style={styles.railCount}>{formatCount(engagement.shareCount)}</Text>
   295|        </TouchableOpacity>
   296|
   297|        <TouchableOpacity style={styles.railBtn} onPress={onToggleMute} testID={`video-mute-${video.id}`}>
   298|          {muted ? <VolumeX size={26} color="#fff" /> : <Volume2 size={26} color="#fff" />}
   299|        </TouchableOpacity>
   300|      </View>
   301|
   302|      {/* Bottom info + CTAs */}
   303|      <View pointerEvents="box-none" style={[styles.info, { bottom: insets.bottom + 32 }]}>
   304|        <LinearGradient
   305|          colors={['transparent', 'rgba(0,0,0,0.55)', 'rgba(0,0,0,0.82)']}
   306|          locations={[0, 0.35, 1]}
   307|          style={styles.bottomGradient}
   308|        />
   309|        <View style={styles.badgeRow}>
   310|          {deal ? <Text style={styles.badgeInvestment}>INVESTMENT</Text> : null}
   311|          {isActiveStatus ? <Text style={styles.badgeActive}>ACTIVE</Text> : null}
   312|        </View>
   313|        <Text style={styles.infoTitle} numberOfLines={1}>
   314|          {`${parsed.title} — ${parsed.tourLabel}`}
   315|        </Text>
   316|        <Text style={styles.infoPropertyTitle} numberOfLines={1}>
   317|          {propertyTitle}
   318|        </Text>
   319|        {parsed.location ? (
   320|          <Text style={styles.infoLocation} numberOfLines={1}>
   321|            {parsed.location}
   322|          </Text>
   323|        ) : null}
   324|        <View style={styles.metricRow}>
   325|          {deal?.expected_roi ? (
   326|            <View style={styles.metric}>
   327|              <Text style={styles.metricValue}>{deal.expected_roi}%</Text>
   328|              <Text style={styles.metricLabel}>ROI</Text>
   329|            </View>
   330|          ) : null}
   331|          {deal?.min_investment && deal.min_investment > 0 ? (
   332|            <View style={styles.metric}>
   333|              <Text style={styles.metricValue}>{compactCurrency(deal.min_investment)}</Text>
   334|              <Text style={styles.metricLabel}>MIN INVEST</Text>
   335|            </View>
   336|          ) : null}
   337|          {deal?.price && deal.price > 0 ? (
   338|            <View style={styles.metric}>
   339|              <Text style={styles.metricValue}>{((deal.min_investment ?? 0) / deal.price * 100).toFixed(4)}%</Text>
   340|              <Text style={styles.metricLabel}>MIN OWNERSHIP</Text>
   341|            </View>
   342|          ) : null}
   343|        </View>
   344|
   345|        <View style={styles.optionsRow}>
   346|          {investmentOptions.map((option) => (
   347|            <View key={option.id} style={styles.optionIcon}>
   348|              <View style={[styles.optionIconCircle, { borderColor: `${option.tint}66` }]}>
   349|                {option.icon}
   350|              </View>
   351|              <Text style={styles.optionIconLabel}>{option.label}</Text>
   352|            </View>
   353|          ))}
   354|        </View>
   355|
   356|        <View style={styles.ctaRowInner}>
   357|          {deal?.url || deal?.id ? (
   358|            <TouchableOpacity
   359|              style={styles.viewDealBtn}
   360|              onPress={() => onViewDeal(video)}
   361|              activeOpacity={0.85}
   362|              testID={`video-view-deal-${video.id}`}
   363|            >
   364|              <Text style={styles.viewDealText}>View Deal</Text>
   365|            </TouchableOpacity>
   366|          ) : null}
   367|          {deal?.id ? (
   368|            <TouchableOpacity
   369|              style={styles.investNowBtn}
   370|              onPress={() => onInvestNow(video)}
   371|              activeOpacity={0.85}
   372|              testID={`video-invest-${video.id}`}
   373|            >
   374|              <Text style={styles.investNowText}>Invest Now</Text>
   375|            </TouchableOpacity>
   376|          ) : null}
   377|        </View>
   378|      </View>
   379|    </View>
   380|  );
   381|});
   382|
   383|export default function VideosScreen() {
   384|  const router = useRouter();
   385|  const insets = useSafeAreaInsets();
   386|  const { height: windowHeight } = useWindowDimensions();
   387|  const params = useLocalSearchParams<{ type?: string }>();
   388|  const [activeIndex, setActiveIndex] = useState<number>(0);
   389|  const [muted, setMuted] = useState<boolean>(true);
   390|  const [userId, setUserId] = useState<string | null>(null);
   391|  const [viewerId, setViewerId] = useState<string | null>(null);
   392|  const [engagements, setEngagements] = useState<Record<string, EngagementState>>({});
   393|  const [toast, setToast] = useState<string | null>(null);
   394|  const [channel, setChannel] = useState<ReelChannel>('all');
   395|
   396|  const [commentsVideo, setCommentsVideo] = useState<FeedVideo | null>(null);
   397|  const [comments, setComments] = useState<ProjectComment[]>([]);
   398|  const [commentsTotal, setCommentsTotal] = useState<number>(0);
   399|  const [commentsLoading, setCommentsLoading] = useState<boolean>(false);
   400|  const [shareVideo, setShareVideo] = useState<FeedVideo | null>(null);
   401|
   402|  const feedQuery = useQuery({
   403|    queryKey: ['ivx-video-feed'],
   404|    queryFn: () => fetchVideoFeed(24),
   405|    staleTime: 60_000,
   406|  });
   407|
   408|  const allVideos: FeedVideo[] = useMemo(() => feedQuery.data ?? [], [feedQuery.data]);
   409|
   410|  const filteredVideos = useMemo(() => {
   411|    if (channel === 'all') return allVideos;
   412|    if (channel === 'investment') return allVideos.filter(v => v.deal && v.video_type !== 'reel');
   413|    if (channel === 'buyer') {
   414|      return allVideos.filter(
   415|        v =>
   416|          (v.deal?.deal_type ?? '').toLowerCase().includes('buy') ||
   417|          v.title?.toLowerCase().includes('buy') ||
   418|          v.title?.toLowerCase().includes('buyer')
   419|      );
   420|    }
   421|    if (channel === 'seller') {
   422|      return allVideos.filter(
   423|        v =>
   424|          (v.deal?.deal_type ?? '').toLowerCase().includes('sell') ||
   425|          v.title?.toLowerCase().includes('sell') ||
   426|          v.title?.toLowerCase().includes('seller')
   427|      );
   428|    }
   429|    return allVideos;
   430|  }, [allVideos, channel]);
   431|
   432|  const counts = useMemo(() => {
   433|    const all = allVideos.length;
   434|    const investment = allVideos.filter(v => v.deal && v.video_type !== 'reel').length;
   435|    const buyer = allVideos.filter(
   436|      v =>
   437|        (v.deal?.deal_type ?? '').toLowerCase().includes('buy') ||
   438|        v.title?.toLowerCase().includes('buy') ||
   439|        v.title?.toLowerCase().includes('buyer')
   440|    ).length;
   441|    const seller = allVideos.filter(
   442|      v =>
   443|        (v.deal?.deal_type ?? '').toLowerCase().includes('sell') ||
   444|        v.title?.toLowerCase().includes('sell') ||
   445|        v.title?.toLowerCase().includes('seller')
   446|    ).length;
   447|    return { all, investment, buyer, seller };
   448|  }, [allVideos]);
   449|
   450|  useEffect(() => {
   451|    let cancelled = false;
   452|    void getViewerId().then((id) => {
   453|      if (!cancelled) setViewerId(id);
   454|    });
   455|    void supabase.auth.getSession().then(({ data }) => {
   456|      if (!cancelled && data.session?.user?.id) setUserId(data.session.user.id);
   457|    }).catch(() => {});
   458|    return () => { cancelled = true; };
   459|  }, []);
   460|
   461|  useEffect(() => {
   462|    if (allVideos.length === 0) return;
   463|    setEngagements(prev => {
   464|      const next = { ...prev };
   465|      for (const v of allVideos) {
   466|        if (!next[v.id]) {
   467|          next[v.id] = {
   468|            likeCount: v.like_count ?? 0,
   469|            commentCount: v.comment_count ?? 0,
   470|            shareCount: v.share_count ?? 0,
   471|            saveCount: v.save_count ?? 0,
   472|            liked: false,
   473|            saved: false,
   474|            following: false,
   475|          };
   476|        }
   477|      }
   478|      return next;
   479|    });
   480|  }, [allVideos]);
   481|
   482|  useEffect(() => {
   483|    const activeVideo = filteredVideos[activeIndex];
   484|    if (!activeVideo) return;
   485|    void trackVideoEvent('view', activeVideo.id);
   486|  }, [activeIndex, filteredVideos]);
   487|
   488|  const showToast = useCallback((message: string) => {
   489|    setToast(message);
   490|    setTimeout(() => setToast(null), 2500);
   491|  }, []);
   492|
   493|  const onViewableItemsChanged = useRef(({ viewableItems }: { viewableItems: ViewToken[] }) => {
   494|    const first = viewableItems.find(v => v.isViewable);
   495|    if (first && typeof first.index === 'number') setActiveIndex(first.index);
   496|  }).current;
   497|
   498|  const viewabilityConfig = useRef({ itemVisiblePercentThreshold: 60 }).current;
   499|
   500|  const handleLike = useCallback(async (video: FeedVideo) => {
   501|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   502|    setEngagements(prev => {
   503|      const cur = prev[video.id] ?? { likeCount: video.like_count ?? 0, commentCount: video.comment_count ?? 0, shareCount: video.share_count ?? 0, saveCount: video.save_count ?? 0, liked: false, saved: false, following: false };
   504|      return {
   505|        ...prev,
   506|        [video.id]: { ...cur, liked: !cur.liked, likeCount: cur.likeCount + (cur.liked ? -1 : 1) },
   507|      };
   508|    });
   509|    try {
   510|      const result = await toggleProjectLike(video.id, userId);
   511|      setEngagements(prev => ({
   512|        ...prev,
   513|        [video.id]: { ...(prev[video.id] as EngagementState), liked: result.liked, likeCount: result.likeCount },
   514|      }));
   515|    } catch {}
   516|  }, [userId]);
   517|
   518|  const handleDoubleTapLike = useCallback((video: FeedVideo) => {
   519|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
   520|    void trackVideoEvent('double_tap_like', video.id);
   521|    const cur = engagements[video.id];
   522|    if (!cur || !cur.liked) {
   523|      void handleLike(video);
   524|    }
   525|  }, [engagements, handleLike]);
   526|
   527|  const handleComment = useCallback(async (video: FeedVideo) => {
   528|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
   529|    setCommentsLoading(true);
   530|    setCommentsVideo(video);
   531|    try {
   532|      const { comments: cmts, total } = await fetchProjectComments(video.id, 20, 0);
   533|      setComments(cmts);
   534|      setCommentsTotal(total);
   535|    } catch {} finally {
   536|      setCommentsLoading(false);
   537|    }
   538|  }, []);
   539|
   540|  const handleAddComment = useCallback(async (projectId: string, body: string, parentId?: string) => {
   541|    try {
   542|      await addProjectComment(projectId, body, userId, undefined, parentId);
   543|      const { comments: cmts, total } = await fetchProjectComments(projectId, 20, 0);
   544|      setComments(cmts);
   545|      setCommentsTotal(total);
   546|      setEngagements(prev => {
   547|        const cur = prev[projectId];
   548|        return cur ? { ...prev, [projectId]: { ...cur, commentCount: total } } : prev;
