   120|async function loadEngagementCounts(sb: any, ids: string[]): Promise<Record<string, { likes: number; comments: number; shares: number; saves: number }>> {
   121|  const counts: Record<string, { likes: number; comments: number; shares: number; saves: number }> = {};
   122|  for (const id of ids) counts[id] = { likes: 0, comments: 0, shares: 0, saves: 0 };
   123|  if (ids.length === 0) return counts;
   124|  const [likesRes, commentsRes, sharesRes, savesRes] = await Promise.all([
   125|    sb.from('project_likes').select('project_id').in('project_id', ids),
   126|    sb.from('project_comments').select('project_id').in('project_id', ids).eq('is_approved', true).is('deleted_at', null),
   127|    sb.from('project_shares').select('project_id').in('project_id', ids),
   128|    sb.from('project_saves').select('project_id').in('project_id', ids),
   129|  ]);
   130|  for (const row of likesRes.data || []) { const k = String(row.project_id); if (counts[k]) counts[k].likes += 1; }
   131|  for (const row of commentsRes.data || []) { const k = String(row.project_id); if (counts[k]) counts[k].comments += 1; }
   132|  for (const row of sharesRes.data || []) { const k = String(row.project_id); if (counts[k]) counts[k].shares += 1; }
   133|  for (const row of savesRes.data || []) { const k = String(row.project_id); if (counts[k]) counts[k].saves += 1; }
   134|  return counts;
   135|}
