   139|function decodeCursor(raw: string | null): number {
   140|  if (!raw) return 0;
   141|  try {
   142|    const parsed = JSON.parse(Buffer.from(raw, 'base64url').toString('utf-8')) as { o?: number };
   143|    return Math.max(0, Number(parsed.o) || 0);
   144|  } catch {
   145|    return 0;
   146|  }
   147|}
   148|
   149|function encodeCursor(offset: number): string {
   150|  return Buffer.from(JSON.stringify({ o: offset }), 'utf-8').toString('base64url');
