   153|/** GET /api/ivx/video-platform/feed — ranked, personalized, cursor-paginated. */
   154|type FeedDeal = {
   155|  id: string;
   156|  title: string | null;
   157|  price: number | null;
   158|  min_investment: number | null;
   159|  expected_roi: string | null;
   160|  deal_type: string | null;
