   164|/**
   165| * Load JV deal info for the video page — matched by meta.property_id or the
   166| * video's project_id against jv_deals.id. Falls back to fuzzy title/project-name
   167| * matching because project_videos.project_id is often the video's own UUID, not the
   168| * deal slug. Returns a map keyed by videoId. Never throws; missing deals → null.
   169| */
   170|async function loadFeedDeals(sb: any, candidates: string[], titles: Record<string, string>): Promise<Record<string, FeedDeal>> {
   171|  const out: Record<string, FeedDeal> = {};
   172|  const idRe = /^[A-Za-z0-9][A-Za-z0-9_-]{1,63}$/;
   173|  const ids = Array.from(new Set(candidates.filter((c) => idRe.test(c))));
   174|  const allDeals: any[] = [];
   175|
   176|  try {
   177|    const { data } = await sb
   178|      .from('jv_deals')
   179|      .select('id,title,project_name,estimated_value,appraised_value,total_investment,min_investment,expected_roi,type')
   180|      .limit(200);
   181|    for (const d of data ?? []) {
   182|      const id = String(d.id);
   183|      const deal: FeedDeal = {
   184|        id,
   185|        title: d.title ?? d.project_name ?? null,
   186|        price: d.estimated_value ?? d.appraised_value ?? d.total_investment ?? null,
   187|        min_investment: d.min_investment ?? null,
   188|        expected_roi: d.expected_roi != null ? String(d.expected_roi) : null,
   189|        deal_type: d.type ?? null,
   190|        url: `https://ivxholding.com/?deal=${id}#deals`,
   191|      };
   192|      allDeals.push({ ...d, __deal: deal });
   193|      // Exact match by id: assign to any video whose candidate id matches the deal id
   194|      if (ids.includes(id)) {
   195|        for (const p of Object.entries(titles)) {
   196|          const [videoId, _title] = p;
   197|          if (!out[videoId]) out[videoId] = deal;
   198|        }
   199|      }
   200|    }
   201|
   202|    // Fuzzy fallback: match video titles against deal title/project_name.
   203|    for (const [videoId, title] of Object.entries(titles)) {
   204|      if (out[videoId] || !title) continue;
   205|      const t = title.toLowerCase();
   206|      const words = t.split(/[^a-z0-9]+/).filter((w) => w.length > 2);
   207|      let best: { deal: FeedDeal; score: number } | null = null;
   208|      for (const d of allDeals) {
   209|        const dealTitle = String(d.title ?? d.project_name ?? '').toLowerCase();
   210|        const dealName = String(d.project_name ?? '').toLowerCase();
   211|        const matches = words.filter((w) => dealTitle.includes(w) || dealName.includes(w)).length;
   212|        const score = matches / Math.max(words.length, 1);
   213|        if (score >= 0.3 && (!best || score > best.score)) {
   214|          best = { deal: d.__deal, score };
   215|        }
   216|      }
   217|      if (best) {
   218|        out[videoId] = best.deal;
   219|      }
   220|    }
   221|  } catch {
   222|    /* deal enrichment is best-effort */
   223|  }
   224|  return out;
   225|}
