   227|export async function handlePlatformFeed(req: Request): Promise<Response> {
   228|  try {
   229|    const url = new URL(req.url);
   230|    const limit = Math.min(Math.max(Number(url.searchParams.get('limit') || '6'), 1), 20);
   231|    const offset = decodeCursor(url.searchParams.get('cursor'));
   232|    const channel = str(url.searchParams.get('channel')).toLowerCase() || null;
   233|    const projectId = str(url.searchParams.get('project_id')) || null;
   234|    const viewerId = str(url.searchParams.get('viewer_id')) || null;
   235|    const zipParam = str(url.searchParams.get('zip')) || null;
   236|
   237|    // ?type=reel → Project Reels rail only; default → investor deal feed with featured interleave.
   238|    const typeParam = str(url.searchParams.get('type')).toLowerCase();
   239|    const reelsOnly = typeParam === 'reel' || typeParam === 'reels';
   240|
   241|    const sb = await getSB();
   242|    let query = sb
   243|      .from('project_videos')
   244|      .select('*')
   245|      .eq('is_approved', true)
   246|      .order('is_pinned', { ascending: false })
   247|      .order('created_at', { ascending: false })
   248|      .limit(200);
   249|    if (projectId) query = query.eq('project_id', projectId);
   250|    const { data: vids, error } = await query;
   251|    if (error) return json({ error: error.message, marker: VIDEO_PLATFORM_MARKER }, 500);
   252|
   253|    const videos: any[] = vids ?? [];
   254|    const ids = videos.map((v) => String(v.id));
   255|
   256|    const [counts, playback, metaDoc, analyticsDoc, profile, followState] = await Promise.all([
   257|      loadEngagementCounts(sb, ids),
   258|      loadPlaybackIndex(),
   259|      getMetaDoc(),
   260|      getAnalyticsDoc(),
   261|      viewerId ? getViewerProfile(viewerId) : Promise.resolve(null),
   262|      viewerId ? getFollowState(viewerId) : Promise.resolve({ following: [] as string[] }),
   263|    ]);
   264|
   265|    const now = Date.now();
   266|    const metaFor = (id: string): VideoMeta => normalizeVideoMeta(metaDoc[id]);
   267|
   268|    // Admin visibility controls: hide switch, draft status, publish schedule, expiration.
   269|    let filtered = videos.filter((v) => isMetaVisible(metaFor(String(v.id)), now));
   270|    // Channel filter: audience-tagged videos for that channel; untagged videos stay in "for you" only.
   271|    if (channel && (VIDEO_AUDIENCES as readonly string[]).includes(channel)) {
   272|      filtered = filtered.filter((v) => metaFor(String(v.id)).audiences.includes(channel));
   273|    }
   274|    // Stories never appear in the main feed.
   275|    filtered = filtered.filter((v) => {
   276|      const m = metaFor(String(v.id));
   277|      return !(m.is_story && m.story_expires_at && Date.parse(m.story_expires_at) > now);
   278|    });
   279|
   280|    // Canonical NEUTRAL ranking context — no viewer personalization, so every
   281|    // platform (landing / Android / iOS / desktop) gets the IDENTICAL order.
   282|    // viewer_id is still used below for liked/saved flags only.
   283|    const ctx: RankContext = {
   284|      channel,
   285|      zip: zipParam,
   286|      profile: null,
   287|      watched: [],
   288|      following: new Set<string>(),
   289|      stats: analyticsDoc.videos,
   290|      meta: metaDoc,
   291|    };
   292|
   293|    const rankable: (RankableVideo & { row: any; display_order: number | null; meta: VideoMeta })[] = filtered.map((v) => {
   294|      const m = metaFor(String(v.id));
   295|      return {
   296|        id: String(v.id),
   297|        created_at: String(v.created_at),
   298|        like_count: counts[String(v.id)]?.likes ?? 0,
   299|        comment_count: counts[String(v.id)]?.comments ?? 0,
   300|        share_count: counts[String(v.id)]?.shares ?? 0,
   301|        save_count: counts[String(v.id)]?.saves ?? 0,
   302|        is_pinned: v.is_pinned === true,
   303|        display_order: m.display_order,
   304|        meta: m,
   305|        row: v,
   306|      };
   307|    });
   308|
   309|    // Type split: investor deal videos vs project reels vs featured investor videos.
   310|    const reels = canonicalSort(rankable.filter((r) => r.meta.video_type === 'reel'), ctx);
   311|    const dealVideos = canonicalSort(rankable.filter((r) => r.meta.video_type !== 'reel' && !r.meta.is_featured), ctx);
   312|    const featured = canonicalSort(rankable.filter((r) => r.meta.video_type !== 'reel' && r.meta.is_featured), ctx);
   313|
   314|    // Unified investor-first composition: 3 deal videos → 1 featured investor video → repeat.
   315|    const composed = reelsOnly ? reels : composeUnifiedFeed(dealVideos, featured);
   316|
   317|    // Viewer state (liked / saved) for the page being returned.
   318|    const page = composed.slice(offset, offset + limit);
   319|    const pageIds = page.map((p) => p.id);
   320|    const dealCandidates: string[] = [];
   321|    const titles: Record<string, string> = {};
   322|    for (const p of page) {
   323|      const m = p.meta;
   324|      if (m.property_id) dealCandidates.push(String(m.property_id));
   325|      if (p.row.project_id) dealCandidates.push(String(p.row.project_id));
   326|      titles[p.id] = p.row.title ?? m.title ?? '';
   327|    }
   328|    const dealsById = await loadFeedDeals(sb, dealCandidates, titles);
   329|    const viewerFollowing = new Set(followState.following);
   330|    void profile;
   331|    let likedSet = new Set<string>();
   332|    let savedSet = new Set<string>();
   333|    if (viewerId && pageIds.length > 0) {
   334|      const [lr, sr] = await Promise.all([
   335|        sb.from('project_likes').select('project_id').in('project_id', pageIds).or(`user_id.eq.${viewerId},guest_id.eq.${viewerId}`),
   336|        sb.from('project_saves').select('project_id').in('project_id', pageIds).or(`user_id.eq.${viewerId},guest_id.eq.${viewerId}`),
   337|      ]);
   338|      likedSet = new Set((lr.data || []).map((r: any) => String(r.project_id)));
   339|      savedSet = new Set((sr.data || []).map((r: any) => String(r.project_id)));
   340|    }
   341|
   342|    const feed = page.map((p) => {
   343|      const v = p.row;
   344|      const pb = playback[p.id];
   345|      const m = p.meta;
   346|      const stats = analyticsDoc.videos[p.id];
   347|      const deal = dealsById[p.id] ?? null;
   348|      return {
   349|        id: p.id,
   350|        project_id: v.project_id ? String(v.project_id) : null,
   351|        video_url: v.video_url,
   352|        hls_url: pb?.status === 'ready' ? pb.hls_url : null,
   353|        poster_url: pb?.poster_url ?? null,
   354|        preview_blur_url: (pb as { preview_blur_url?: string | null } | undefined)?.preview_blur_url ?? null,
   355|        playback_status: pb?.status ?? null,
   356|        thumbnail_url: v.thumbnail_url ?? pb?.thumbnail_url ?? null,
   357|        title: v.title ?? null,
   358|        duration_sec: v.duration_sec ?? 0,
   359|        width: v.width ?? null,
   360|        height: v.height ?? null,
   361|        orientation: v.orientation ?? 'landscape',
   362|        is_pinned: p.is_pinned,
   363|        created_at: v.created_at,
   364|        like_count: p.like_count,
   365|        comment_count: p.comment_count,
   366|        share_count: p.share_count,
   367|        save_count: p.save_count,
   368|        view_count: stats?.views ?? 0,
   369|        audiences: m.audiences,
   370|        property_id: m.property_id,
   371|        creator_id: m.creator_id,
   372|        zip: m.zip,
   373|        video_type: m.video_type,
   374|        is_featured: m.is_featured,
   375|        display_order: m.display_order,
   376|        publish_at: m.publish_at,
   377|        expires_at: m.expires_at,
   378|        status: m.status,
   379|        viewer_liked: likedSet.has(p.id),
   380|        viewer_saved: savedSet.has(p.id),
   381|        viewer_following_creator: !!(m.creator_id && viewerFollowing.has(m.creator_id)),
   382|        deal,
   383|      };
   384|    });
   385|
   386|    const nextOffset = offset + page.length;
   387|    return json({
   388|      videos: feed,
   389|      count: feed.length,
   390|      total: composed.length,
   391|      next_cursor: nextOffset < composed.length ? encodeCursor(nextOffset) : null,
   392|      channel,
   393|      feed_type: reelsOnly ? 'reel' : 'unified',
   394|      ordering: 'canonical-unified-v2',
   395|      personalized: false,
   396|      marker: VIDEO_PLATFORM_MARKER,
   397|    });
   398|  } catch (err) {
   399|    return json({ error: err instanceof Error ? err.message : 'feed failed', marker: VIDEO_PLATFORM_MARKER }, 500);
   400|  }
   401|}
