   428|
   429|function firstPhoto(raw: unknown): string | null {
   430|  if (Array.isArray(raw)) {
   431|    const p = raw.find((x) => typeof x === 'string' && x.startsWith('http'));
   432|    return p ? String(p) : null;
   433|  }
   434|  if (typeof raw === 'string') {
   435|    try { return firstPhoto(JSON.parse(raw)); } catch { return raw.startsWith('http') ? raw : null; }
   436|  }
   437|  return null;
   438|}
   439|
   440|function toHomeFeedDeal(row: Record<string, unknown>, meta: DealMeta): HomeFeedDeal {
   441|  const id = String(row.id);
   442|  const total = num(row.total_investment) ?? num(row.estimated_value) ?? num(row.appraised_value);
   443|  const raised = num(row.amount_raised) ?? num(row.funds_raised) ?? num(row.raised_amount);
   444|  const explicitProgress = num(row.progress_percent) ?? num(row.funding_progress) ?? num(row.construction_progress);
   445|  const progress = explicitProgress ?? (raised != null && total != null && total > 0
   446|    ? Math.min(100, Math.round((raised / total) * 100))
   447|    : null);
   448|  const city = typeof row.city === 'string' && row.city
   449|    ? (typeof row.state === 'string' && row.state ? `${row.city}, ${row.state}` : String(row.city))
   450|    : (typeof row.property_address === 'string' ? String(row.property_address) : null);
   451|  const phase = [row.construction_phase, row.phase, row.project_phase, row.stage]
   452|    .map((v) => (typeof v === 'string' && v.trim() ? v.trim() : null))
   453|    .find((v) => v != null) ?? null;
   454|  return {
   455|    id,
   456|    name: (row.project_name ?? row.title ?? null) as string | null,
   457|    city,
   458|    phase,
   459|    status: (row.status ?? null) as string | null,
   460|    deal_type: (row.type ?? null) as string | null,
   461|    investment_amount: total,
   462|    expected_roi: row.expected_roi != null ? String(row.expected_roi) : null,
   463|    min_investment: num(row.min_investment),
   464|    progress_percent: progress,
   465|    photo_url: firstPhoto(row.photos),
   466|    url: `https://ivxholding.com/?deal=${id}#deals`,
   467|    is_featured: meta.is_featured,
   468|    priority: meta.priority,
   469|    display_order: meta.display_order,
   470|    created_at: (row.created_at ?? null) as string | null,
