   479|function sortHomeFeedDeals(deals: HomeFeedDeal[]): HomeFeedDeal[] {
   480|  return [...deals].sort((a, b) => {
   481|    if (a.is_featured !== b.is_featured) return a.is_featured ? -1 : 1;
   482|    if (a.priority !== b.priority) return b.priority - a.priority;
   483|    const ao = a.display_order;
   484|    const bo = b.display_order;
   485|    if (ao !== null || bo !== null) {
   486|      if (ao === null) return 1;
   487|      if (bo === null) return -1;
   488|      if (ao !== bo) return ao - bo;
