   599|/**
   600| * Ingest one MPEG-TS segment over HTTP: store it in S3, extend the EVENT HLS
   601| * playlist, and flip the session to 'live' on the first segment.
   602| */
   603|export async function ingestLiveSegment(sessionId: string, bytes: Uint8Array, durationSeconds: number): Promise<LiveSession> {
   604|  const doc = await readDoc<LiveDoc>('live.json', {});
   605|  const raw = doc[sessionId];
   606|  if (!raw) throw new Error('live session not found');
   607|  const session = normalizeLiveSession(raw);
   608|  if (session.status === 'ended' || session.status === 'failed') {
   609|    throw new Error(`live session is ${session.status}; ingest rejected`);
   610|  }
   611|  if (session.ingest_url === null) throw new Error('session uses an external playback_url; ingest not enabled');
   612|  if (session.segments.length >= MAX_LIVE_SEGMENTS) throw new Error('live session segment limit reached');
   613|
   614|  const seq = session.segment_count;
   615|  const duration = Number.isFinite(durationSeconds) && durationSeconds > 0 ? Math.min(durationSeconds, 30) : 4;
   616|  const segmentKey = `${LIVE_STORAGE_PREFIX}/${sessionId}/seg_${String(seq).padStart(5, '0')}.ts`;
   617|  try {
   618|    await putLiveObject(segmentKey, bytes, 'video/mp2t', 'public, max-age=31536000, immutable');
   619|    session.segments.push({ seq, duration, size: bytes.byteLength, uploaded_at: nowIso() });
   620|    session.segment_count = seq + 1;
   621|    session.last_segment_at = nowIso();
   622|    if (session.status === 'created') {
   623|      session.status = 'live';
   624|      session.started_at = nowIso();
   625|    }
   626|    await putLiveObject(`${LIVE_STORAGE_PREFIX}/${sessionId}/live.m3u8`, buildLivePlaylist(session, false), 'application/vnd.apple.mpegurl', 'no-cache');
   627|  } catch (err) {
   628|    session.status = 'failed';
   629|    session.ended_at = nowIso();
   630|    session.ended_reason = `ingest failed: ${err instanceof Error ? err.message : 'storage error'}`;
   631|    doc[sessionId] = session;
   632|    await writeDoc('live.json', doc);
   633|    await syncLiveSessionRow(session);
   634|    throw err;
   635|  }
   636|  doc[sessionId] = session;
   637|  await writeDoc('live.json', doc);
   638|  await syncLiveSessionRow(session);
   639|  return session;
