   727|/**
   728| * Recommendation score: recency decay + engagement + watch quality
   729| * + audience/zip/preference match + followed-creator boost − already-seen penalty.
   730| */
   731|export function scoreVideo(video: RankableVideo, ctx: RankContext): number {
   732|  const meta = ctx.meta[video.id];
   733|  const stats = ctx.stats[video.id];
