   735|
   736|  const ageHours = Math.max(0, (Date.now() - Date.parse(video.created_at)) / 3_600_000);
   737|  score += 40 * Math.exp(-ageHours / 168);
   738|
   739|  const engagement = video.like_count * 3 + video.comment_count * 4 + video.share_count * 5 + video.save_count * 4;
   740|  score += Math.log1p(engagement) * 10;
   741|
   742|  if (stats) {
   743|    score += Math.log1p(stats.views) * 4;
   744|    score += Math.log1p(stats.completions) * 6;
   745|    score += Math.log1p(stats.watch_ms / 1000) * 2;
   746|  }
   747|
   748|  if (meta) {
   749|    if (ctx.channel && meta.audiences.includes(ctx.channel)) score += 30;
   750|    if (ctx.profile?.audience && meta.audiences.includes(ctx.profile.audience)) score += 18;
   751|    if (ctx.zip && meta.zip) {
   752|      if (meta.zip === ctx.zip) score += 25;
   753|      else if (meta.zip.slice(0, 3) === ctx.zip.slice(0, 3)) score += 12;
   754|    }
   755|    if (ctx.profile?.preferences?.length && meta.property_id && ctx.profile.preferences.includes(meta.property_id)) score += 10;
