   176|      .from(bucket)
   177|      .upload(fileName, blob, {
   178|        contentType: mediaType === 'video' ? 'video/mp4' : 'image/jpeg',
   179|        upsert: false,
   180|      });
   181|
   182|    if (uploadError) throw new Error(uploadError.message);
   183|
   184|    const { data: urlData } = supabase.storage.from(bucket).getPublicUrl(fileName);
   185|    const publicUrl = urlData.publicUrl;
   186|
   187|    // Create media record
