/**
 * useNetworkState — tracks device network connectivity.
 *
 * Used to pause playback and show retry UI when the network drops,
 * and to resume when it returns. Prevents infinite buffering loops
 * on flaky cellular connections.
 */
import { useEffect, useState } from 'react';
import { NetInfo, type NetInfoState } from 'expo-netinfo';

export type NetworkType = 'wifi' | 'cellular' | 'ethernet' | 'unknown' | 'none';

export interface NetworkStatus {
  isConnected: boolean;
  isInternetReachable: boolean;
  type: NetworkType;
}

export function useNetworkState(): NetworkStatus {
  const [status, setStatus] = useState<NetworkStatus>({
    isConnected: true,
    isInternetReachable: true,
    type: 'unknown',
  });

  useEffect(() => {
    let cancelled = false;

    const handleUpdate = (state: NetInfoState) => {
      if (cancelled) return;
      setStatus({
        isConnected: state.isConnected ?? false,
        isInternetReachable: state.isInternetReachable ?? false,
        type: (state.type as NetworkType) ?? 'unknown',
      });
    };

    // Fetch initial state
    void NetInfo.fetch().then(handleUpdate).catch(() => {});

    const unsubscribe = NetInfo.addEventListener(handleUpdate);

    return () => {
      cancelled = true;
      unsubscribe();
    };
  }, []);

  return status;
}

