  if (!videoRef.current) return;
  const status = await videoRef.current.getStatusAsync();
  if (!status.isLoaded) return;
  if (status.isPlaying) {
    await videoRef.current.pauseAsync();
  } else {
    await videoRef.current.playAsync();
  }
}, []);

